+    if (typeof svgString !== 'string') return '';
+
+    // Prefer DOM-based sanitization when running in a browser-like environment.
+    if (typeof DOMParser === 'function' && typeof XMLSerializer === 'function') {
+        const parser = new DOMParser();
+        const doc = parser.parseFromString(svgString, 'image/svg+xml');
+
+        // If parsing fails, return an empty SVG (do not keep potentially dangerous input).
+        if (doc.getElementsByTagName('parsererror').length) {
+            return '<svg xmlns="http://www.w3.org/2000/svg"></svg>';
+        }
+
+        const svgEl = doc.documentElement;
+
+        // Remove elements commonly used for script/HTML injection.
+        // (foreignObject can contain HTML; script can execute JS)
+        const forbidden = ['script', 'foreignObject'];
+        for (const tag of forbidden) {
+            const nodes = svgEl.getElementsByTagName(tag);
+            // live NodeList: remove from end to start
+            for (let i = nodes.length - 1; i >= 0; i--) {
+                const n = nodes[i];
+                if (n && n.parentNode) n.parentNode.removeChild(n);
+            }
+        }
+
+        // Strip event handler attributes and javascript: hrefs.
+        const walker = doc.createTreeWalker(svgEl, NodeFilter.SHOW_ELEMENT, null, false);
+        let node = walker.currentNode;
+        while (node) {
+            if (node.attributes) {
+                // Copy attributes first since we'll be removing them while iterating.
+                const attrs = Array.from(node.attributes);
+                for (const attr of attrs) {
+                    const name = attr.name;
+                    const value = attr.value || '';
+                    if (/^on/i.test(name)) {
+                        node.removeAttribute(name);
+                        continue;
+                    }
+                    if ((name === 'href' || name === 'xlink:href') && /^\s*javascript:/i.test(value)) {
+                        node.removeAttribute(name);
+                    }
+                }
+            }
+            node = walker.nextNode();
+        }
